AND cp.category = #{category}
AND (cp.title LIKE CONCAT('%', #{keyword}, '%') OR cp.content LIKE CONCAT('%', #{keyword}, '%') OR cp.company_name LIKE CONCAT('%', #{keyword}, '%') OR cp.job_title LIKE CONCAT('%', #{keyword}, '%') OR cp.tags_json LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY cp.like_count DESC, cp.created_at DESC
ORDER BY cp.comment_count DESC, cp.created_at DESC
ORDER BY cp.view_count DESC, cp.created_at DESC
ORDER BY cp.created_at DESC
LIMIT #{limit} OFFSET #{offset}

