UPDATE community_post
   SET status = #{status}
 WHERE id = #{id}

UPDATE community_post
   SET view_count = view_count + 1
 WHERE id = #{id}

mapper.select:
SELECT cp.*,
       u.name AS user_name
  FROM community_post cp
  JOIN users u ON cp.user_id = u.id
 WHERE cp.status = #{status}
   AND cp.created_at >= #{since}
 ORDER BY (cp.recommend_count * 5 + cp.like_count * 3 + cp.comment_count * 2 + cp.view_count) DESC
 LIMIT #{limit}

mapper.update:
UPDATE community_post
   SET comment_count = comment_count + 1
 WHERE id = #{id}

UPDATE community_post
   SET comment_count = GREATEST(comment_count - 1, 0)
 WHERE id = #{id}

UPDATE community_post
   SET like_count = like_count + 1
 WHERE id = #{id}

UPDATE community_post
   SET like_count = GREATEST(like_count - 1, 0)
 WHERE id = #{id}

UPDATE community_post
   SET bookmark_count = bookmark_count + 1
 WHERE id = #{id}

UPDATE community_post
   SET bookmark_count = GREATEST(bookmark_count - 1, 0)
 WHERE id = #{id}

UPDATE community_post
   SET tags_json = #{tagsJson}
 WHERE id = #{id}

UPDATE community_interview_review
   SET ai_extracted_questions = #{aiExtractedQuestions}
 WHERE post_id = #{postId}

mapper.select:
SELECT cp.id, cp.title, cp.content, e.embedding FROM community_post cp JOIN community_post_embedding e ON e.post_id = cp.id WHERE cp.status = 'PUBLISHED'
AND cp.category = #{category}
AND (
cp.title LIKE CONCAT('%', #{kw}, '%') OR cp.content LIKE CONCAT('%', #{kw}, '%') OR cp.tags_json LIKE CONCAT('%', #{kw}, '%')
)
ORDER BY cp.created_at DESC LIMIT #{limit}
